#!/usr/bin/perl
use strict;
use warnings;
use CAM::PDF;

# Function to extract date and author from the PDF
sub extract_info {
    my ($pdf) = @_;
    my $info = $pdf->getPageAsText(1);  # Get the first page as text
    $info =~ s/\r//g;  # Remove carriage returns
    $info =~ s/\n/ /g;  # Replace newlines with spaces

    # Extract author and date
    my ($author, $date);
    if ($info =~ /Author:\s*(.*?)\s*Created:\s*(.*?)\s*/) {
        ($author, $date) = ($1, $2);
    }

    return ($author, $date);
}

# Function to extract table data
sub extract_table {
    my ($pdf, $page) = @_;
    my $table = $pdf->getPageAsText($page);  # Get the specified page as text
    $table =~ s/\r//g;  # Remove carriage returns
    $table =~ s/\n/ /g;  # Replace newlines with spaces

    # Extract table data (this is a simple example, more sophisticated parsing may be needed)
    my @table_data = split(/\s+/, $table);
    return @table_data;
}

