my $pdf = CAM::PDF->new($pdf_filename);

# Extract info
my ($author, $date) = extract_info($pdf);
print "Author: $author\n";
print "Date: $date\n";

# Extract table information from the first page
my @table_data = extract_table($pdf, 1);
print "Table Data on Page 1:\n";
